changeSet.sql:
CREATE TABLE nexus.taxonomy_meta (
    tenant_id                TEXT             NOT NULL,
    collection               TEXT             NOT NULL,
    last_discover_doc_count  INTEGER          NOT NULL DEFAULT 0,
    last_discover_at         TIMESTAMPTZ,
    CONSTRAINT taxonomy_meta_pk PRIMARY KEY (tenant_id, collection)
);

CREATE INDEX idx_taxonomy_meta_tenant ON nexus.taxonomy_meta (tenant_id);

CREATE TABLE nexus.topic_links (
    tenant_id     TEXT    NOT NULL,
    from_topic_id BIGINT  NOT NULL REFERENCES nexus.topics(id) ON DELETE CASCADE,
    to_topic_id   BIGINT  NOT NULL REFERENCES nexus.topics(id) ON DELETE CASCADE,
    link_count    INTEGER NOT NULL DEFAULT 0,
    link_types    TEXT    NOT NULL DEFAULT '[]',
    CONSTRAINT topic_links_pk PRIMARY KEY (tenant_id, from_topic_id, to_topic_id)
);

-- get_topic_link_pairs: both from/to in a set
CREATE INDEX idx_tl_tenant_from ON nexus.topic_links (tenant_id, from_topic_id);
CREATE INDEX idx_tl_tenant_to   ON nexus.topic_links (tenant_id, to_topic_id);

-- topics
ALTER TABLE nexus.topics ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.topics FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.topics
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- taxonomy_meta
ALTER TABLE nexus.taxonomy_meta ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.taxonomy_meta FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.taxonomy_meta
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- topic_assignments
ALTER TABLE nexus.topic_assignments ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.topic_assignments FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.topic_assignments
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

-- topic_links
ALTER TABLE nexus.topic_links ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.topic_links FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.topic_links
    USING      (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

changeSet.rollback:
DROP POLICY IF EXISTS tenant_isolation ON nexus.topic_links;
ALTER TABLE nexus.topic_links NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.topic_links DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.topic_assignments;
ALTER TABLE nexus.topic_assignments NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.topic_assignments DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.taxonomy_meta;
ALTER TABLE nexus.taxonomy_meta NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.taxonomy_meta DISABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS tenant_isolation ON nexus.topics;
ALTER TABLE nexus.topics NO FORCE ROW LEVEL SECURITY;
ALTER TABLE nexus.topics DISABLE ROW LEVEL SECURITY;

changeSet.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'nexus_svc') THEN
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.topics TO nexus_svc';
        EXECUTE 'GRANT USAGE ON SEQUENCE nexus.topics_id_seq TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.taxonomy_meta TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.topic_assignments TO nexus_svc';
        EXECUTE 'GRANT SELECT, INSERT, UPDATE, DELETE ON nexus.topic_links TO nexus_svc';
        RAISE NOTICE 'Granted nexus taxonomy table privileges to nexus_svc';
    ELSE
        RAISE NOTICE 'nexus_svc role not found; skipping grants';
    END IF;
END
$$;
